mapper.select:
SELECT
agent.is_top, agent.top_time,
r.resource_id, r.system_code, r.resource_source_pk_id, r.resource_biz_type, r.resource_type, r.resource_name, r.resource_desc, r.avatar, r.sample, r.tags, r.resource_version_id, r.host_type, src.catalog_id, src.catalog_name, src.catalog_type, r.man_org_id, po.org_name as man_org_name, r.man_user_id, r.index_list, r.create_by, r.create_time, r.update_by, r.update_time, r.com_acct_id, r.resource_status, r.resource_d_verid, r.resource_r_verid, r.resource_code, r.auth_status, r.publish_portal, srede.create_type, CASE WHEN r.resource_biz_type = 'AGENT' THEN a.agent_type ELSE NULL END as agent_type, r.publish_time, r.shelf_time, r.unshelf_time, b.plugin_machine_id, b.type, b.kdb_id, t.task_id, ont.pid, t.deal_desc FROM ss_resource r
LEFT JOIN suas_superassist_sub_agent agent on agent.agent_id =r.resource_id
LEFT JOIN ss_res_ext_agent a ON r.resource_id = a.resource_id AND r.resource_biz_type = 'AGENT' LEFT JOIN ss_res_ext_doc b ON r.resource_id = b.resource_id AND r.resource_biz_type in ('KG_DOC', 'KG_DB', 'KG_QA') LEFT JOIN ss_res_ext_dig_employee srede ON r.resource_id = srede.resource_id AND r.resource_biz_type = 'DIG_EMPLOYEE' LEFT JOIN po_organization po on po.org_id = r.man_org_id LEFT JOIN ss_resource_catalog src on src.catalog_id = r.catalog_id LEFT JOIN ss_res_ext_ontology ont ON r.resource_id = ont.resource_id LEFT JOIN ( SELECT t1.task_id, t1.deal_desc, t1.resource_id FROM men_task t1 INNER JOIN ( SELECT resource_id, MAX(task_id) as max_task_id FROM men_task WHERE resource_id IS NOT NULL GROUP BY resource_id ) t2 ON t1.resource_id = t2.resource_id AND t1.task_id = t2.max_task_id ) t ON t.resource_id = r.resource_id
and r.parent_resource_id =-1 and resource_status !=6
and r.resource_name like concat('%', concat(#{query.resourceName}, '%'))
AND ont.pid = #{query.pid}
and r.com_acct_id = #{query.enterpriseId}
and r.system_code in
#{item}
and r.resource_biz_type in
#{item}
and (r.owner_type is null or r.owner_type = 'enterprise')
and (src.catalog_path IN ( SELECT sc.catalog_path FROM ss_resource_catalog sc WHERE sc.catalog_id IN
#{item}
) OR src.catalog_path LIKE ANY ( SELECT CONCAT(sc.catalog_path, '.%') FROM ss_resource_catalog sc WHERE sc.catalog_id IN
#{item}
) )
and r.resource_id in
#{item}
and r.resource_biz_type = #{query.resourceBizType}
and r.resource_status in
#{item}
and r.create_by = #{query.userId}
and r.man_user_id = #{query.userId}
and r.create_by != #{query.userId}
and r.catalog_id = #{query.catalogId}
ORDER BY
r.create_time r.update_time r.resource_name r.resource_status r.publish_time r.shelf_time
COALESCE(agent.is_top, 0)
agent.top_time
r.create_time
ASC DESC
ORDER BY r.create_time DESC, r.update_time DESC

select b.resource_code, b.resource_id from ss_resource_rel_detail a join ss_resource b on a.rel_resource_id = b.resource_id
and a.resource_id in
#{item}

select a.resource_rel_detail_id, b.resource_biz_type, b.resource_id, b.resource_code, b.resource_status, b.resource_name, a.resource_id, a.rel_resource_id from ss_resource_rel_detail a join ss_resource b on a.rel_resource_id = b.resource_id
and b.resource_status = 2
and a.resource_id in
#{item}
and b.resource_biz_type = #{type}

select a.resource_rel_detail_id, b.resource_biz_type, a.resource_id, a.rel_resource_id, b.resource_code, b.resource_status, b.resource_name from ss_resource_rel_detail a join ss_resource b on a.rel_resource_id = b.resource_id
and a.resource_id in
#{item}
and b.resource_biz_type = #{type}

SELECT b.resource_code, b.resource_id, b.resource_biz_type AS rel_resource_biz_type, c.resource_biz_type AS resource_biz_type FROM ss_resource_rel_detail a JOIN ss_resource b ON a.rel_resource_id = b.resource_id AND b.resource_biz_type = 'TOOL' JOIN ss_resource c ON a.resource_id = c.resource_id AND c.resource_biz_type = 'TOOLKIT'
AND a.resource_id IN
#{item}
AND b.resource_status IN
#{status}

SELECT
r.resource_status,
count(1) as num
FROM ss_resource r
LEFT JOIN ss_res_ext_ontology ont ON r.resource_id = ont.resource_id

    and r.parent_resource_id =-1 and resource_status !=6

        and r.resource_name like concat('%', concat(#{query.resourceName}, '%'))



        and r.resource_biz_type in

            #{item}


            and (r.owner_type is null or r.owner_type = 'enterprise')



        and ont.pid = #{query.pid}






                and (r.resource_id in

                    #{item}

                or r.create_by = #{query.userId})


                and r.create_by = #{query.userId}


                and r.resource_id in

                    #{item}






                and r.resource_id in

                    #{item}




                and r.create_by = #{query.userId}




group by r.resource_status

SELECT
agent.is_top, agent.top_time,
r.resource_id, r.system_code, r.resource_source_pk_id, r.resource_biz_type, r.resource_type, r.resource_name, r.resource_desc, r.avatar, r.sample, r.tags, r.resource_version_id, r.host_type, src.catalog_id, src.catalog_name, src.catalog_type, r.man_org_id, ont.pid, po.org_name as man_org_name, r.man_user_id, r.index_list, r.create_by, r.create_time, r.update_by, r.update_time, r.com_acct_id, r.resource_status, r.resource_d_verid, r.resource_r_verid, r.resource_code, r.auth_status, r.publish_portal, srede.create_type, CASE WHEN r.resource_biz_type = 'AGENT' THEN a.agent_type ELSE NULL END as agent_type, r.publish_time, r.shelf_time, r.unshelf_time, b.plugin_machine_id, b.type, b.kdb_id, t.task_id, t.deal_desc FROM ss_resource r
LEFT JOIN suas_superassist_sub_agent agent on agent.agent_id =r.resource_id
LEFT JOIN ss_res_ext_agent a ON r.resource_id = a.resource_id AND r.resource_biz_type = 'AGENT' LEFT JOIN ss_res_ext_doc b ON r.resource_id = b.resource_id AND r.resource_biz_type in ('KG_DOC', 'KG_DB', 'KG_QA') LEFT JOIN ss_res_ext_dig_employee srede ON r.resource_id = srede.resource_id AND r.resource_biz_type = 'DIG_EMPLOYEE' LEFT JOIN po_organization po on po.org_id = r.man_org_id LEFT JOIN ss_resource_catalog src on src.catalog_id = r.catalog_id LEFT JOIN ss_res_ext_ontology ont ON r.resource_id = ont.resource_id LEFT JOIN ( SELECT t1.task_id, t1.deal_desc, t1.resource_id FROM men_task t1 INNER JOIN ( SELECT resource_id, MAX(task_id) as max_task_id FROM men_task WHERE resource_id IS NOT NULL GROUP BY resource_id ) t2 ON t1.resource_id = t2.resource_id AND t1.task_id = t2.max_task_id ) t ON t.resource_id = r.resource_id
and r.parent_resource_id =-1 and resource_status !=6
AND r.resource_biz_type IN
#{type}
AND ont.pid = #{request.pid}
AND r.resource_biz_type = #{request.bizType}
and r.system_code in
#{item}
and (src.catalog_path IN ( SELECT sc.catalog_path FROM ss_resource_catalog sc WHERE sc.catalog_id IN
#{item}
) OR src.catalog_path LIKE ANY ( SELECT CONCAT(sc.catalog_path, '.%') FROM ss_resource_catalog sc WHERE sc.catalog_id IN
#{item}
))
AND r.resource_status IN
#{status}
AND (
r.create_by = #{request.userId}
OR
r.resource_id IN
#{id}
)
AND r.resource_name LIKE CONCAT('%', #{request.resourceName}, '%')
ORDER BY
r.create_time r.update_time r.resource_name r.resource_status r.publish_time r.shelf_time
COALESCE(agent.is_top, 0)
agent.top_time
r.create_time
ASC DESC
ORDER BY r.create_time DESC, r.update_time DESC

SELECT a.resource_id, a.resource_name, a.resource_desc, a.resource_status, a.avatar, a.resource_code, sssa.is_top, b.max_create_time, d.agent_type, d.terminal, sssa.top_time FROM ss_resource a INNER JOIN ( SELECT grant_obj_id, MAX(create_date) AS max_create_time FROM au_privilege_grant
AND status_cd = 'A' AND grant_type IN ('AVAILABLE_USE', 'FORCE_USE')
AND grant_to_obj_id IN
#{id}
AND grant_obj_id IN
#{id}
GROUP BY grant_obj_id ) b ON b.grant_obj_id = a.resource_id LEFT JOIN suas_superassist_sub_agent sssa ON sssa.agent_id = a.resource_id AND sssa.status_cd = '00A' AND sssa.superassist_id = #{userId} LEFT JOIN ss_res_ext_dig_employee d ON d.resource_id = a.resource_id
AND a.resource_status = 2 AND a.resource_biz_type = 'DIG_EMPLOYEE'
AND a.resource_name LIKE CONCAT('%', #{name}, '%')
AND a.create_by = #{userId}
AND a.create_by != #{userId}
AND d.terminal IN
#{terminal}
ORDER BY COALESCE(CAST(sssa.is_top AS INTEGER), 0) DESC, CASE WHEN COALESCE(CAST(sssa.is_top AS INTEGER), 0) = 1 THEN sssa.top_time ELSE NULL END DESC NULLS LAST, COALESCE(b.max_create_time, TIMESTAMP '1970-01-01 00:00:00') DESC

SELECT
distinct r.system_code,
ss.system_name
FROM ss_resource r
INNER JOIN po_source_system ss ON ss.system_code = r.system_code
LEFT JOIN po_organization po ON po.org_id = r.man_org_id
LEFT JOIN ss_resource_catalog src ON src.catalog_id = r.catalog_id

    AND r.system_code is not null


        and r.resource_name like concat('%', #{query.keyword}, '%')



        and r.resource_biz_type in

            #{item}





        and (
        src.catalog_path IN (
        SELECT sc.catalog_path
        FROM ss_resource_catalog sc
        WHERE sc.catalog_id IN

            #{item}

        )
        OR src.catalog_path LIKE ANY (
        SELECT CONCAT(sc.catalog_path, '.%')
        FROM ss_resource_catalog sc
        WHERE sc.catalog_id IN

            #{item}

        )
        )



        and (
        po.path_code = (
        SELECT pp.path_code
        FROM po_organization pp
        WHERE pp.org_id = #{query.orgId}
        )
        OR po.path_code LIKE ANY(
        SELECT CONCAT(pp_inner.path_code, '.%')
        FROM po_organization pp_inner
        WHERE pp_inner.org_id = #{query.orgId}
        )
        )



        and r.resource_status in

            #{item}

select a.resource_id as resourceId, a.resource_name as name, a.resource_code as code, a.resource_desc as desc, a.catalog_id as catalogId, a.resource_status as status, b.catalog_type as catalogType, b.catalog_name as catalogName, CASE a.resource_type WHEN 'API' THEN 1 WHEN 'DOCUMENT' THEN 2 WHEN 'DB_TABLE' THEN 3 WHEN 'COMMON_DB' THEN 4 ELSE NULL END AS type from ss_resource a left join ss_resource_catalog b on a.catalog_id = b.catalog_id where a.resource_id in
#{item}
and a.resource_biz_type = 'OBJECT'

SELECT a.resource_id, a.resource_source_pk_id, a.system_code, a.resource_biz_type, a.resource_type, a.resource_name, a.resource_code, a.resource_desc, a.avatar, a.sample, a.tags, a.resource_version_id, a.host_type, a.catalog_id, a.man_org_id, a.man_user_id, a.index_list, a.create_by, a.create_time, a.update_by, a.update_time, a.com_acct_id, a.resource_status, a.resource_d_verid, a.resource_r_verid, a.resource_code, a.publish_time, a.shelf_time, a.unshelf_time, a.auth_status, a.publish_portal, a.parent_resource_id, a.publish_type, a.owner_type FROM ( SELECT DISTINCT rel_resource_id FROM ss_resource_rel_detail WHERE resource_id = #{resourceId} ) d INNER JOIN ss_resource a ON d.rel_resource_id = a.resource_id WHERE 1 = 1 AND a.resource_status = 2 AND a.resource_biz_type IN ('KG_DOC', 'KG_QA', 'OBJECT', 'VIEW', 'TOOLKIT', 'MCP', 'AGENT')
AND a.catalog_id IN
#{catalogIdItem}
AND a.catalog_id = #{catalogId}
AND a.resource_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY CASE WHEN a.resource_biz_type IN ('KG_DOC', 'KG_QA') THEN 0 ELSE 1 END, a.update_time DESC, a.resource_id DESC

SELECT rrd.resource_id as employeeId, sr.resource_biz_type as resourceBizType, COUNT(*) as count FROM ss_resource_rel_detail rrd INNER JOIN ss_resource sr ON rrd.rel_resource_id = sr.resource_id WHERE rrd.resource_id IN
#{employeeId}
AND sr.resource_biz_type IN ('KG_DOC', 'KG_QA', 'KG_TERM', 'AGENT', 'MCP', 'TOOLKIT', 'TOOL', 'OBJECT', 'VIEW') AND sr.resource_status = 2 AND sr.parent_resource_id < 0 GROUP BY rrd.resource_id, sr.resource_biz_type ORDER BY rrd.resource_id, sr.resource_biz_type

SELECT * FROM ss_resource
WHERE resource_code = #{resourceCode}
  AND resource_status = #{resourceStatus}
LIMIT 1

SELECT * FROM ss_resource
where   resource_status = 3 and  resource_code in

    #{code}

SELECT resource_id FROM byai.ss_resource
WHERE resource_biz_type = #{resourceBizType}
AND resource_name LIKE CONCAT('%', #{resourceName}, '%')

    AND resource_id IN

        #{resourceId}

SELECT resource_id, create_by FROM byai.ss_resource
WHERE resource_id IN

    #{resourceId}

AND publish_portal = #{publishPortal}

SELECT * FROM ss_resource
WHERE resource_id = #{resourceId}
LIMIT 1
